mapper.select:
		SELECT CASE WHEN COUNT(*) > 0 THEN 1 ELSE 0 END
		FROM VW_SECURITY_AUTH v
		JOIN G_PROJECT gp ON v.GROUP_NO = gp.GROUP_NO
    	JOIN PROJECT p ON gp.PROJECT_NO = p.PROJECT_NO
		WHERE v.user_id = #{userId}
		AND p.project_code = #{value}
		AND v.menu_id = #{menuId}
		AND (
		(#{method} = 'READ' AND V.CRUD_READ = 1) OR
		(#{method} = 'CREATE' AND V.CRUD_CREATE = 1) OR
		(#{method} = 'UPDATE' AND V.CRUD_UPDATE = 1) OR
		(#{method} = 'DELETE' AND V.CRUD_DELETE = 1)
		)
